// Prüfen ob ein PDF-Anhang vorhanden ist
const item = $input.first();

const attachmentKeys = Object.keys(item.binary || {});
const pdfKey = attachmentKeys.find(k => {
  const mime = item.binary[k]?.mimeType || '';
  const name = item.binary[k]?.fileName || '';
  return mime === 'application/pdf' || name.toLowerCase().endsWith('.pdf');
});

if (!pdfKey) {
  return [{ json: { anhang_vorhanden: false, grund: 'Kein PDF-Anhang gefunden' } }];
}

const attachment = item.binary[pdfKey];
const absender = item.json?.from || 'unbekannt';
const betreff = item.json?.subject || 'Rechnung';
const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const dateiname = (attachment.fileName || 'rechnung.pdf').replace(/[^a-zA-Z0-9._-]/g, '_');
const finaler_dateiname = `${timestamp}_${dateiname}`;

return [{
  json: {
    anhang_vorhanden: true,
    pdf_key: pdfKey,
    dateiname,
    finaler_dateiname,
    absender,
    betreff
  },
  binary: item.binary
}];

// Google Drive Link und File-ID aus der Upload-Antwort extrahieren
const item = $input.first();
const fileId = item.json?.id;
const fileName = item.json?.name;

if (!fileId) throw new Error('Google Drive Upload fehlgeschlagen – keine File-ID erhalten');

const driveUrl = `https://drive.google.com/uc?export=download&id=${fileId}`;

console.log(`[Gmail-Workflow] PDF in Google Drive: ${fileName} (${fileId})`);

return [{
  json: {
    drive_file_id: fileId,
    drive_url: driveUrl,
    dateiname: fileName,
    absender: $('PDF-Anhang prüfen').item.json.absender,
    betreff: $('PDF-Anhang prüfen').item.json.betreff
  }
}];

const item = $input.first();
console.log(`[Gmail-Workflow] E-Mail ohne PDF ignoriert: ${item.json.grund}`);
return [{ json: { status: 'ignoriert', ...item.json } }];
